results.candidate_sql:
SELECT (COUNT(CASE WHEN s."FundingType" = 'Locally funded' THEN 1 END) * 100.0 / COUNT(*)) AS ratio_percentage
FROM schools s
WHERE s."County" = 'Santa Clara' AND s."Charter" = 1;

SELECT ROUND(100.0 * SUM(CASE WHEN b.bond_type = '=' THEN 1 ELSE 0 END) / COUNT(b.bond_id), 5) AS percentage
FROM bond b
WHERE b.molecule_id = 'TR008';

SELECT (COUNT(DISTINCT CASE WHEN b.bond_type = '#' THEN m.molecule_id END) * 100.0 / COUNT(DISTINCT m.molecule_id)) AS percent_triple_bond
FROM molecule m
LEFT JOIN bond b ON m.molecule_id = b.molecule_id;

SELECT 
    (SELECT COUNT(*) FROM posts WHERE OwnerUserId = 24) * 1.0 / 
    (SELECT COUNT(*) FROM votes WHERE UserId = 24) AS post_to_vote_ratio;

SELECT (COUNT(DISTINCT b.UserId) * 100.0 / (SELECT COUNT(*) FROM users)) AS percentage
FROM badges b
WHERE b.Name = 'Teacher';

SELECT 
    (SELECT COUNT(*) FROM superhero sh JOIN publisher p ON sh.publisher_id = p.id WHERE p.publisher_name = 'Marvel Comics') -
    (SELECT COUNT(*) FROM superhero sh JOIN publisher p ON sh.publisher_id = p.id WHERE p.publisher_name = 'DC Comics') AS difference;

SELECT 
    (SELECT weight_kg FROM superhero WHERE full_name = 'Emil Blonsky') - 
    (SELECT weight_kg FROM superhero WHERE full_name = 'Charles Chandler') AS weight_difference;

SELECT 100.0 * COUNT(CASE WHEN c.colour = 'Blue' THEN 1 END) / COUNT(*) AS percentage
FROM superhero s
JOIN colour c ON s.eye_colour_id = c.id;

SELECT (COUNT(DISTINCT CASE WHEN p."SEX" = 'F' AND (l."TP" < 6.0 OR l."TP" > 8.5) THEN p."ID" END) * 100.0 / COUNT(DISTINCT p."ID")) AS percentage
FROM "Patient" p
LEFT JOIN "Laboratory" l ON p."ID" = l."ID";

SELECT 100.0 * SUM(CASE WHEN l."UA" <= 6.5 THEN 1 ELSE 0 END) / COUNT(*) AS percentage
FROM "Laboratory" l
WHERE l."U-PRO" > '0' AND l."U-PRO" < '30';

SELECT 100.0 * SUM(CASE WHEN p.SEX = 'F' THEN 1 ELSE 0 END) / COUNT(*) AS percentage
FROM Patient p
WHERE YEAR(p.Birthday) = 1980 AND p.Diagnosis = 'RA';

SELECT 
    (SELECT COALESCE(SUM(b.spent), 0) FROM budget b JOIN event e ON b.link_to_event = e.event_id WHERE SUBSTR(e.event_date, 1, 4) = '2019') -
    (SELECT COALESCE(SUM(b.spent), 0) FROM budget b JOIN event e ON b.link_to_event = e.event_id WHERE SUBSTR(e.event_date, 1, 4) = '2020') AS difference;

SELECT (SUM(CASE WHEN m.position = 'Member' AND ma.major_name = 'Business' THEN 1 ELSE 0 END) * 100.0 / COUNT(*)) AS percentage
FROM member m
JOIN major ma ON m.link_to_major = ma.major_id;

SELECT 
    (SELECT COUNT(*) FROM gasstations WHERE Country = 'CZE' AND Segment = 'Discount') -
    (SELECT COUNT(*) FROM gasstations WHERE Country = 'SVK' AND Segment = 'Discount') AS difference;

SELECT 
    (SELECT COUNT(*) FROM customers WHERE Segment = 'SME' AND Currency = 'CZK') - 
    (SELECT COUNT(*) FROM customers WHERE Segment = 'SME' AND Currency = 'EUR') AS Amount_of_more_SMEs;

SELECT (COUNT(CASE WHEN g."Segment" = 'Premium' THEN 1 END) * 100.0 / COUNT(*)) AS percentage_premium
FROM gasstations g
WHERE g."Country" = 'Slovakia';
